#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
int n,m,dp[505][105][105],ans;
string s;
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n>>m>>s;
	s=" "+s;
	memset(dp,128,sizeof(dp));
	dp[0][0][0]=dp[1][0][0]=0;
	for(int i=2;i<=n;i++)
	{
		for(int j=0;j<=m;j++)
		{
			for(int k=0;k<=m;k++)
			{
				dp[i][j][k]=dp[i-1][j][k];
				if(s[i-1]=='j')
				{
					if(s[i]=='z') dp[i][j][k]=max(dp[i][j][k],dp[i-2][j][k]+1);
					if(s[i]=='j'&&k>0) dp[i][j][k]=max(dp[i][j][k],dp[i-2][j][k-1]+1);
				}
				else
				{
					if(s[i]=='z') dp[i][j][k]=max(dp[i][j][k],dp[i-2][j-1][k]+1);
					if(s[i]=='j'&&k>0) dp[i][j][k]=max(dp[i][j][k],dp[i-2][j-1][k-1]+1);
				}
			}
		}
	}
	for(int i=2;i<=n;i++)
	{
		for(int j=1;j<=m;j++)
		{
			ans=max(dp[i][j][j],ans);
		}
	}
	cout<<ans;
	return 0;
}
